gsap.defaults({ ease: 'power2.inOut' });

// Animate Chats
const splitTextAnimation = (element, type = 'words', duration, stagger) => {
  let tl = gsap.timeline({
    onStart: () => {
      self.css('opacity', '1');
    },
    onComplete: () => {
      self.addClass('loaded');
    },
  });

  let self = $(element);
  self.css('opacity', '0');

  let split = new SplitText(element, { type: type });
  tl.from(
    split[type],
    { duration: duration, ease: 'linear', visibility: 'hidden', stagger: stagger },
    '<-=0.3'
  );
  if ($(element).find('.w-embed').length) {
    tl.from(
      $(element).find('.w-embed'),
      { duration: duration, y: '0.5em', opacity: 0, stagger: stagger * 10 },
      '<'
    );
  }

  return tl;
};

const overlapPos = '<+=1';

const animateChat = (trigger, duration = 0.2) => {
  // Define animations for each type of element
  let animations = {
    avatar: (element) => gsap.from(element, { duration, scale: 0 }, overlapPos),
    item: (element) => gsap.from(element, { duration, y: '0.5em', opacity: 0 }, overlapPos),
    list: (element) => {
      return splitTextAnimation($(element).find('li'), 'words', duration / 2, duration * 0.03);
    },
    chat: (element) => gsap.from(element, { duration, x: '1em', opacity: 0 }, overlapPos),
    text: (element) => splitTextAnimation(element, 'words', duration / 2, duration * 0.08),
  };

  // Function to animate inner elements sequentially
  function animateInnerElements(block) {
    // Get all inner elements
    let elements = $(block).find('[data-animation]');

    // Create a GSAP timeline
    let tl = gsap.timeline();

    // Loop through each element and add its animation to the timeline
    elements.each((index, element) => {
      // corrected to use index, element
      let animationType = $(element).attr('data-animation');
      if (animations[animationType]) {
        tl.add(animations[animationType](element));
      }
    });

    // Custom Cases
    // Case #1 - Select the Profile
    if ($(block).hasClass('_2')) {
      tl.call(() => {
        $('.hp_hero-person-card').eq(0).addClass('highlighted');
      });
    }

    return tl;
  }

  // Create a main timeline for blocks
  let mainTimeline = gsap.timeline();

  // Add each block animation to the main timeline
  $(trigger)
    .find('[data-animation="block"]')
    .each((index, block) => {
      // corrected to use index, block
      mainTimeline.add(animateInnerElements(block));
    });

  return mainTimeline;
};

$('[data-animation="trigger"]').each(function (index, element) {
  let duration = $(this).attr('data-duration');
  let self = $(this);

  let tl = gsap.timeline({
    scrollTrigger: {
      trigger: $(this),
      start: '20% bottom',
      markers: true,
    },
    onStart: () => {
      $(self).css('opacity', '1');
    },
    delay: index === 0 ? 1 : 0,
  });
  if (duration) {
    tl.add(animateChat($(this), duration));
  } else {
    tl.add(animateChat($(this)));
  }
});

// Animate platforms
const animatePlatform = () => {
  let tl = gsap.timeline({
    scrollTrigger: {
      trigger: $('.hp_dashboard-wrap_inner'),
    },
  });

  tl.from($('.hp_dashboard-item'), { scale: 0, stagger: 0.1 });
  tl.from($('.hp_dashboard_grid-line #dots path'), { scale: 0, stagger: 0.1 }, '-=0.8');
  tl.from(
    ['#horizontal-right', '#horizontal-left', $('#vertical path'), '.hp_dashboard-line'],
    {
      opacity: 0,
    },
    '-=0.2'
  );
  tl.from($('.hp_dashboard-profile_icon'), { scale: 0 }, '<');
};

animatePlatform();

// Counter
const animateCounter = ($element) => {
  $($element).each(function () {
    const currentText = $(this).text().trim().replace(/,/g, '');
    const startValue = 0;
    const targetValue = parseFloat(currentText);

    if (!isNaN(targetValue) && startValue !== targetValue) {
      const Cont = { val: startValue }; // Initialize with current value
      const decimalPlaces = 0;

      const onUpdate = () => {
        let formattedValue = parseFloat(Cont.val.toFixed(decimalPlaces)).toLocaleString('en');
        $(this).text(formattedValue);
      };

      let tl = gsap.timeline({
        scrollTrigger: {
          trigger: $(this).closest('[data-counter="trigger"]'),
          start: 'center bottom',
        },
      });

      tl.from($(this), { opacity: 0, duration: 0.1 });
      tl.fromTo(
        Cont,
        { val: startValue },
        {
          val: targetValue,
          duration: 2,
          ease: Power1.easeOut,
          onUpdate: onUpdate,
        }
      );
    }
  });
};

$('[data-animation="number"]').each(function () {
  animateCounter($(this));
});
